{
  "name": "Gmail Automation Dev Environment",

  // Use custom Dockerfile to install additional packages
  "build": {
    "dockerfile": "Dockerfile",
    "context": "."
  },

  // Mount Docker socket for scripts that manage external containers
  "mounts": [
    "source=/var/run/docker.sock,target=/var/run/docker.sock,type=bind",
    "source=/home/scott/projects/oss/zen-mcp-server,target=/home/scott/projects/oss/zen-mcp-server,type=bind",
    "source=/home/scott/projects/oss/claude-code-tamagotchi,target=/home/scott/projects/oss/claude-code-tamagotchi,type=bind",
    "source=/home/scott/.claude/CLAUDE.md,target=/home/node/.claude/CLAUDE.md,type=bind",
    "source=/home/scott/.claude/settings.json,target=/home/node/.claude/settings.json,type=bind",
    "source=/home/scott/.claude/mcp.json,target=/home/node/.claude/mcp.json,type=bind",
    "source=/home/scott/.claude/statusline.sh,target=/home/node/.claude/statusline.sh,type=bind",
    "source=/home/scott/.claude/commands,target=/home/node/.claude/commands,type=bind",
    "source=/home/scott/.claude/projects,target=/home/node/.claude/projects,type=bind",
    "source=/home/scott/.claude/plugins,target=/home/node/.claude/plugins,type=bind"
  ],

  // Connect to postgres network to access PostgreSQL container directly
  "runArgs": ["--network=postgres_default"],

  // Install Claude Code, uv, Python 3.12, and project dependencies after container creation
  "postCreateCommand": "curl -LsSf https://astral.sh/uv/install.sh | sh && echo 'export PATH=\"$HOME/.cargo/bin:$PATH\"' >> ~/.bashrc && export PATH=\"$HOME/.cargo/bin:$PATH\" && npm install -g @anthropic-ai/claude-code && uv python install 3.12.3 && sudo ln -sf /home/node/.local/bin/python3.12 /usr/bin/python3.12 && npm install && chmod +x scripts/*.sh",

  "customizations": {
    "vscode": {
      "extensions": [
        "esbenp.prettier-vscode",
        "dbaeumer.vscode-eslint",
        "redhat.vscode-yaml",
        "ms-vscode.vscode-typescript-next"
      ],
      "settings": {
        "terminal.integrated.defaultProfile.linux": "bash",
        "editor.formatOnSave": true,
        "editor.defaultFormatter": "esbenp.prettier-vscode",
        "eslint.format.enable": true,
        "editor.codeActionsOnSave": {
          "source.fixAll.eslint": "explicit"
        }
      }
    }
  },

  // Forward ports for services
  "forwardPorts": [5432, 3000],
  "portsAttributes": {
    "5432": { "label": "PostgreSQL", "onAutoForward": "silent" },
    "3000": { "label": "Web App", "onAutoForward": "notify" }
  },

  // Pass through API keys from host environment
  "remoteEnv": {
    "ANTHROPIC_API_KEY": "${localEnv:ANTHROPIC_API_KEY}",
    "PERPLEXITY_API_KEY": "${localEnv:PERPLEXITY_API_KEY}",
    "OPENAI_API_KEY": "${localEnv:OPENAI_API_KEY}",
    "GOOGLE_API_KEY": "${localEnv:GOOGLE_API_KEY}",
    "XAI_API_KEY": "${localEnv:XAI_API_KEY}",
    "OPENROUTER_API_KEY": "${localEnv:OPENROUTER_API_KEY}",
    "MISTRAL_API_KEY": "${localEnv:MISTRAL_API_KEY}",
    "GROQ_API_KEY": "${localEnv:GROQ_API_KEY}",
    // Mark as devcontainer environment for database connection scripts
    "DEVCONTAINER": "true"
  },

  "remoteUser": "node",
  "updateRemoteUserUID": true
}

